def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Use VLM to check whether slide 8 contains headers labeled 'Adults' and 'Children'
    slide_8_image = None
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 8:
                slide_8_image = s.image_path
                break
        except Exception:
            continue
    if not slide_8_image:
        # Infra-vs-model disambiguation: if slide exists in modified pptx,
        # the missing screenshot is an infra failure (raise to retry).
        from pptx import Presentation as _Pres
        try:
            _slide_count = len(_Pres(modified_ppt_path).slides)
        except Exception:
            _slide_count = 0
        if _slide_count >= 8:
            raise ScreenshotsUnavailableError("Slide 8 screenshot not found; flagging task for verification retry.")
        return "Slide 8 screenshot not found.", 0.0

    prompt = (
        "Look at slide 8. If there are two columns of bullet points, are there any visible column headers labeled exactly 'Adults' and 'Children'?\n"
        "Respond YES if both headers are present, PARTIAL if only one is present, or NONE if neither is present.\n"
        "Ignore case and minor styling differences; focus on the presence of the headers."
    )
    try:
        response = vlm_call(images=[slide_8_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().upper()
        if resp.startswith('YES'):
            return response, 1.0
        elif 'PARTIAL' in resp:
            return response, 0.5
        elif resp.startswith('NONE') or resp.startswith('NO'):
            return response, 0.0
        else:
            return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return f"Error during VLM check: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Find slide 8 screenshot
    slide_8_screenshot = None
    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 8:
            slide_8_screenshot = screenshot
            break

    if not slide_8_screenshot:
        return "No screenshot found for slide 8", 0.0

    # Use VLM to evaluate content appropriateness
    prompt = """Analyze this PowerPoint slide with two columns labeled 'Adults' and 'Children'.

    Look at the bullet points or content under each column header:
    1. Does the content under 'Adults' seem relavent to the health of adults?
    2. Does the content under 'Children' seem relavent to the health of children?

    Rate the appropriateness of the content categorization:
    - EXCELLENT: All content is very well categorized
    - FAIR: Some content is appropriately categorized but there are issues
    - POOR: Content is incorrectly categorized."""

    response = vlm_call(prompt, [slide_8_screenshot.image_path])

    response_upper = response.upper()
    if 'EXCELLENT' in response_upper:
        return "Content categorization is excellent", 1.0
    elif 'GOOD' in response_upper:
        return "Content categorization is good", 0.8
    elif 'FAIR' in response_upper:
        return "Content categorization is fair", 0.6
    elif 'POOR' in response_upper:
        return "Content categorization is poor", 0.0
    else:
        return f"Could not determine content categorization quality: {response}", 0.0

def compute_score() -> tuple[str, float]:
    # Check for modifications to slides other than slide 8
    other_slides_modified = []

    for old_slide, new_slide in ppt_diff.modified_slides:
        if old_slide.slide_number != 8 and new_slide.slide_number != 8:
            other_slides_modified.append(old_slide.slide_number)

    # Check for added/removed slides
    slides_added = len(ppt_diff.added_slides)
    slides_removed = len(ppt_diff.removed_slides)

    if not other_slides_modified and slides_added == 0 and slides_removed == 0:
        return "No extraneous changes to other slides", 1.0
    else:
        issues = []
        if other_slides_modified:
            issues.append(f"Modified slides: {other_slides_modified}")
        if slides_added > 0:
            issues.append(f"Added {slides_added} slides")
        if slides_removed > 0:
            issues.append(f"Removed {slides_removed} slides")

        return f"Extraneous changes detected: {', '.join(issues)}", 0.0
